diff --git a/llvm/lib/Transforms/Utils/SimplifyIndVar.cpp b/llvm/lib/Transforms/Utils/SimplifyIndVar.cpp
index 7b9c5c77cbe9..dfc5f60e1c32 100644
--- a/llvm/lib/Transforms/Utils/SimplifyIndVar.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyIndVar.cpp
@@ -270,26 +270,48 @@ void SimplifyIndvar::eliminateIVComparison(ICmpInst *ICmp,
   for (auto *U : ICmp->users())
     Users.push_back(cast<Instruction>(U));
   const Instruction *CtxI = findCommonDominator(Users, *DT);
+  bool Eliminated = false;
   if (auto Ev = SE->evaluatePredicateAt(Pred, S, X, CtxI)) {
-    SE->forgetValue(ICmp);
-    ICmp->replaceAllUsesWith(ConstantInt::getBool(ICmp->getContext(), *Ev));
-    DeadInsts.emplace_back(ICmp);
-    LLVM_DEBUG(dbgs() << "INDVARS: Eliminated comparison: " << *ICmp << '\n');
-  } else if (makeIVComparisonInvariant(ICmp, IVOperand)) {
-    // fallthrough to end of function
-  } else if (ICmpInst::isSigned(OriginalPred) &&
+    bool SkipElim = false;
+    // Narrow safety guard for PR126012: avoid folding (V > 0) to true when
+    // V's conservative SCEV range still includes 0 and SCEV cannot globally
+    // prove V > 0. Keep the compare so later canonicalization (sgt->ugt) can
+    // still occur.
+    if (*Ev && (Pred == ICmpInst::ICMP_SGT || Pred == ICmpInst::ICMP_UGT)) {
+      if (auto *ConstX = dyn_cast<SCEVConstant>(X)) {
+        if (ConstX->getAPInt().isZero() && !SE->isKnownPredicate(Pred, S, X)) {
+          ConstantRange R = ICmpInst::isSigned(Pred) ? SE->getSignedRange(S)
+                                                     : SE->getUnsignedRange(S);
+          if (R.getLower().isZero()) {
+            LLVM_DEBUG(dbgs() << "INDVARS: Keep (V > 0) comparison; 0 may still occur: "
+                              << *ICmp << '\n');
+            SkipElim = true; // Do not eliminate; fall through for canonicalization.
+          }
+        }
+      }
+    }
+    if (!SkipElim) {
+      SE->forgetValue(ICmp);
+      ICmp->replaceAllUsesWith(ConstantInt::getBool(ICmp->getContext(), *Ev));
+      DeadInsts.emplace_back(ICmp);
+      LLVM_DEBUG(dbgs() << "INDVARS: Eliminated comparison: " << *ICmp << '\n');
+      Eliminated = true;
+    }
+  }
+
+  if (!Eliminated && makeIVComparisonInvariant(ICmp, IVOperand)) {
+    Eliminated = true; // Comparison simplified to invariant form.
+  } else if (!Eliminated && ICmpInst::isSigned(OriginalPred) &&
              SE->isKnownNonNegative(S) && SE->isKnownNonNegative(X)) {
-    // If we were unable to make anything above, all we can is to canonicalize
-    // the comparison hoping that it will open the doors for other
-    // optimizations. If we find out that we compare two non-negative values,
-    // we turn the instruction's predicate to its unsigned version. Note that
-    // we cannot rely on Pred here unless we check if we have swapped it.
+    // Canonicalize signed non-negative comparisons to unsigned.
     assert(ICmp->getPredicate() == OriginalPred && "Predicate changed?");
-    LLVM_DEBUG(dbgs() << "INDVARS: Turn to unsigned comparison: " << *ICmp
-                      << '\n');
     ICmp->setPredicate(ICmpInst::getUnsignedPredicate(OriginalPred));
-  } else
-    return;
+    LLVM_DEBUG(dbgs() << "INDVARS: Turn to unsigned comparison: " << *ICmp << '\n');
+    Eliminated = true; // Count canonicalization as elimination like before.
+  }
+
+  if (!Eliminated)
+    return; // Nothing changed.

   ++NumElimCmp;
   Changed = true;

